#include<bits/stdc++.h>
using namespace std;
int a[450010];
map<int,int> cnt;
struct segment_tree
{
    struct node
    {
        int l,r,lson,rson,tag;
        int min1,cnt;
    }a[1350010];
    int cnt;
    segment_tree():cnt(0){}
    void pushup(int x)
    {
        a[x].min1=min(a[a[x].lson].min1,a[a[x].rson].min1);
        a[x].cnt=0;
	    if(a[a[x].lson].min1==a[x].min1)
        {
            a[x].cnt+=a[a[x].lson].cnt;
        }
        if(a[a[x].rson].min1==a[x].min1)
        {
            a[x].cnt+=a[a[x].rson].cnt;
        }
    }
    void pushup(node &x,node l,node r)
    {
        x.min1=min(l.min1,r.min1);
		x.cnt=0;
        if(l.min1==x.min1)
        {
            x.cnt+=l.cnt;
        }
        if(r.min1==x.min1)
        {
            x.cnt+=r.cnt;
        }
    }
	void pushadd(int x,int val)
	{
		a[x].tag+=val;
		a[x].min1+=val;
	}
	void pushdown(int x)
	{
		int ls=a[x].lson,rs=a[x].rson;
		int tg=a[x].tag;
		pushadd(ls,tg);
		pushadd(rs,tg);
		a[x].tag=0;
	}
    int init(int l,int r)
    {
        int x=++cnt;
        a[x].l=l;
        a[x].r=r;
		a[x].tag=0;
        if(l==r)
        {
            a[x].min1=0;
            a[x].cnt=1;
            return x;
        }
        int mid=(l+r)>>1;
        a[x].lson=init(l,mid);
        a[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
	void add(int x,int l,int r,int v)
	{
		if(a[x].l>r||a[x].r<l)
		{
			return;
		}
		if(l<=a[x].l&&a[x].r<=r)
		{
			pushadd(x,v);
			return;
		}
		pushdown(x);
		add(a[x].lson,l,r,v);
		add(a[x].rson,l,r,v);
		pushup(x);
	}
	node query(int x,int l,int r)
	{
		if(l<=a[x].l&a[x].r<=r)
		{
			return a[x];
		}
		int mid=(a[x].l+a[x].r)>>1;
		pushdown(x);
		if(l<=mid&&r>mid)
		{
			node ans=a[x];
			pushup(ans,query(a[x].lson,l,r),query(a[x].rson,l,r));
			return ans;
		}
		else if(l<=mid)
		{
			return query(a[x].lson,l,r);
		}
		else
		{
			return query(a[x].rson,l,r);
		}
	}
}t;
int main()
{
    int n,m;
	scanf("%d%d",&n,&m);
	// printf("n=%d m=%d\n",n,m);
	t.init(1,450000);
	int l=150001,r=150000+n,p=150000;
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&a[i]);
		cnt[a[i]]++;
	}
	for(int i=1;i<=n;i++)
	{
		t.add(1,i-cnt[i]+1+p,i+p,1);
	}
	int c=0;
	while(m--)
	{
		int op,x;
		scanf("%d%d",&op,&x);
		if(op>0)
		{
			x-=c;
			if(a[op]+c<=n)
			{
				t.add(1,a[op]-cnt[a[op]]+1+p,a[op]+p,-1);
			}
			if(x+c<=n)
			{
				t.add(1,x-cnt[x]+1+p,x+p,-1);
			}
			cnt[a[op]]--;
			cnt[x]++;
			if(a[op]+c<=n)
			{
				t.add(1,a[op]-cnt[a[op]]+1+p,a[op]+p,1);
			}
			if(x+c<=n)
			{
				t.add(1,x-cnt[x]+1+p,x+p,1);
			}
			a[op]=x;
		}
		else
		{
			c+=x;
			l-=x;
			r-=x;
			if(x==-1&&cnt[n-c])
			{
				t.add(1,(n-c)-cnt[n-c]+1+p,(n-c)+p,1);
			}
			if(x==1&&cnt[n+1-c])
			{
				t.add(1,(n+1-c)-cnt[n+1-c]+1+p,(n+1-c)+p,-1);
			}
			// p-=x;
		}
		segment_tree::node tmp=t.query(1,l,r);
		// printf("debug:");
		// for(int i=1;i<=n*3;i++)
		// {
		// 	printf("%d ",t.query(1,l,r).min1);
		// }
		// printf("\n");
		if(tmp.min1==0)
		{
			printf("%d\n",tmp.cnt);
		}
		else
		{
			printf("0\n");
		}
	}
    return 0;
}
